from pydantic import BaseModel
from openai import OpenAI
import instructor

client = instructor.from_openai(OpenAI())


class Citation(BaseModel):
    source_title: str
    page_or_section: str | None
    quote: str          # verbatim excerpt from the source (max 60 words)
    relevance: str      # one sentence: why this source supports the answer


class CitedAnswer(BaseModel):
    answer: str
    citations: list[Citation]
    not_found_in_sources: bool  # True if answer could not be grounded


def answer_with_citations(question: str, retrieved_docs: list[dict]) -> CitedAnswer:
    """
    retrieved_docs: list of {"title": str, "content": str, "url": str}
    """
    doc_block = "\n\n".join(
        f"SOURCE: {d['title']}\n{d['content']}" for d in retrieved_docs
    )
    return client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {
                "role": "system",
                "content": (
                    "Answer the question based ONLY on the provided sources. "
                    "For each factual claim, cite the specific source. "
                    "If the answer cannot be found in the sources, set not_found_in_sources=true."
                ),
            },
            {
                "role": "user",
                "content": f"Sources:\n{doc_block}\n\nQuestion: {question}",
            },
        ],
        response_model=CitedAnswer,
    )


# In the UI, render citations as expandable footnotes
def render_citations(answer: CitedAnswer) -> str:
    if answer.not_found_in_sources:
        return f"{answer.answer}\n\n⚠️ Could not verify in available sources."
    cite_block = "\n".join(
        f"[{i+1}] {c.source_title} — {c.page_or_section or ''}\n    \"{c.quote}\""
        for i, c in enumerate(answer.citations)
    )
    return f"{answer.answer}\n\nSources:\n{cite_block}"

from enum import Enum
from pydantic import BaseModel


class ConfidenceTier(str, Enum):
    HIGH = "high"       # ≥0.85 — state as fact, no badge needed
    MEDIUM = "medium"   # 0.65–0.84 — light hedging
    LOW = "low"         # <0.65 — explicit "please verify" warning


class ConfidentAnswer(BaseModel):
    answer: str
    confidence: float   # 0.0–1.0
    uncertainty_reason: str | None   # why confidence is low, if applicable


def confidence_tier(score: float) -> ConfidenceTier:
    if score >= 0.85:
        return ConfidenceTier.HIGH
    if score >= 0.65:
        return ConfidenceTier.MEDIUM
    return ConfidenceTier.LOW


UI_SIGNALS = {
    ConfidenceTier.HIGH: {
        "badge": None,              # no badge — confident outputs need no marker
        "prefix": "",
        "color": "inherit",
    },
    ConfidenceTier.MEDIUM: {
        "badge": "ℹ️ Review suggested",
        "prefix": "Based on available data, ",
        "color": "amber",
    },
    ConfidenceTier.LOW: {
        "badge": "⚠️ Please verify",
        "prefix": "I'm not fully certain, but ",
        "color": "red",
    },
}


def format_with_confidence(answer: ConfidentAnswer) -> dict:
    tier = confidence_tier(answer.confidence)
    signal = UI_SIGNALS[tier]
    return {
        "text": signal["prefix"] + answer.answer,
        "badge": signal["badge"],
        "color": signal["color"],
        "tooltip": answer.uncertainty_reason,
    }

// Collapsible process trace in the UI
interface TraceStep {
  type: "tool_call" | "retrieval" | "reasoning" | "final_answer";
  label: string;        // human-readable: "Searched knowledge base"
  detail?: string;      // optional: query used, document titles, etc.
  durationMs?: number;
}

function ProcessTrace({ steps }: { steps: TraceStep[] }) {
  const [expanded, setExpanded] = React.useState(false);

  return (
    <details open={expanded} onToggle={e => setExpanded((e.target as HTMLDetailsElement).open)}>
      <summary className="trace-summary">
        🔍 {steps.length} step{steps.length !== 1 ? "s" : ""} taken
        {!expanded && " — expand to see"}
      </summary>
      <ol className="trace-steps">
        {steps.map((step, i) => (
          <li key={i} className={`trace-step trace-step-${step.type}`}>
            <span className="step-label">{step.label}</span>
            {step.detail && (
              <span className="step-detail text-sm text-gray-500"> — {step.detail}</span>
            )}
            {step.durationMs && (
              <span className="step-duration text-xs"> ({step.durationMs}ms)</span>
            )}
          </li>
        ))}
      </ol>
    </details>
  );
}

// Example trace steps generated from a RAG query:
const exampleTrace: TraceStep[] = [
  { type: "retrieval", label: "Searched knowledge base", detail: "query: return policy", durationMs: 220 },
  { type: "retrieval", label: "Found 3 relevant documents", detail: "Return Policy v4, FAQ, T&C" },
  { type: "reasoning", label: "Selected top 2 documents" },
  { type: "final_answer", label: "Generated answer" },
];

// Full explainability UI component
interface ExplainableResponseProps {
  answer: string;
  reasons?: string[];
  citations?: Array<{ title: string; excerpt: string }>;
  confidence?: number;
  traceSteps?: TraceStep[];
}

function ExplainableResponse({
  answer,
  reasons,
  citations,
  confidence,
  traceSteps,
}: ExplainableResponseProps) {
  return (
    <div className="explainable-response">
      {/* Primary answer — always visible */}
      <p className="answer">{answer}</p>

      {/* Confidence badge — only if < 0.85 */}
      {confidence !== undefined && confidence < 0.85 && (
        <span className={`confidence-badge confidence-${confidence < 0.65 ? "low" : "medium"}`}>
          {confidence < 0.65 ? "⚠️ Please verify" : "ℹ️ Review suggested"}
        </span>
      )}

      {/* Why? — collapsed by default */}
      {reasons && reasons.length > 0 && (
        <details>
          <summary>Why this answer?</summary>
          <ul>{reasons.map(r => <li key={r}>{r}</li>)}</ul>
        </details>
      )}

      {/* Sources — collapsed */}
      {citations && citations.length > 0 && (
        <details>
          <summary>Sources ({citations.length})</summary>
          {citations.map(c => (
            <blockquote key={c.title}>
              <p>{c.excerpt}</p>
              <cite>{c.title}</cite>
            </blockquote>
          ))}
        </details>
      )}

      {/* Process trace — collapsed */}
      {traceSteps && <ProcessTrace steps={traceSteps} />}
    </div>
  );
}
